package ru.lifegame.assets.domain.model.asset;

import java.util.List;

/**
 * Schema definition for sprite-atlas.json — the versioned atlas configuration
 * generated by the asset pipeline and consumed by the frontend SpriteController.
 * <p>
 * <b>Config Version: 1.3</b>
 * <p>
 * Changes from 1.2:
 * <ul>
 *   <li>Added {@code displayScale} — multiplier applied by the frontend when
 *       rendering sprites. Allows small pixel-art frames (32×48) to be displayed
 *       at a size proportional to the scene background (e.g. 320×240).
 *       Default: 1.0 (no scaling).
 *       Characters typically use 2.5–3.0, locations use 1.0.</li>
 * </ul>
 * <p>
 * Changes from 1.1:
 * <ul>
 *   <li>Added {@code renderMode} to AnimationEntry: "sprite" (default) or "overlay".</li>
 *   <li>Added {@code tint} and {@code opacity} to RowDef for overlay animations.</li>
 *   <li>Renamed top-level {@code character} to {@code entity}.</li>
 * </ul>
 * <p>
 * Structure:
 * <pre>
 * {
 *   "configVersion": "1.3",
 *   "revision": "latest",
 *   "entity": "tanya",
 *   "displayScale": 3.0,
 *   "animations": {
 *     "idle": {
 *       "file": "idle_atlas.png",
 *       "layout": "grid",
 *       "renderMode": "sprite",
 *       "columns": 6,
 *       "frameWidth": 32,
 *       "frameHeight": 48,
 *       "rows": [
 *         {
 *           "rowIndex": 0,
 *           "condition": { "type": "time_of_day", "value": "morning" },
 *           "fps": 8,
 *           "loop": true
 *         }
 *       ],
 *       "defaultRow": 0
 *     }
 *   }
 * }
 * </pre>
 * <p>
 * <b>Versioning strategy:</b>
 * <ul>
 *   <li>{@code configVersion} — schema version (semver). Frontend checks major: 1.* OK.</li>
 *   <li>{@code revision} — build revision. "latest" (default) = always use newest.
 *       Numbered revisions (e.g. "20260306-1") allow pinning for production.</li>
 * </ul>
 */
public record AtlasConfigSchema(
        String configVersion,
        String revision,
        String entity,
        double displayScale,
        java.util.Map<String, AnimationEntry> animations
) {
    public static final String CURRENT_VERSION = "1.3";
    public static final String LATEST_REVISION = "latest";
    public static final double DEFAULT_DISPLAY_SCALE = 1.0;

    /**
     * Single animation entry within the config.
     *
     * @param file        atlas PNG filename (relative to animations/ dir)
     * @param layout      "grid" or "strip"
     * @param renderMode  "sprite" (default — CSS background-position) or
     *                    "overlay" (CSS backgroundColor + opacity + blend mode)
     * @param columns     number of frame columns in the atlas
     * @param frameWidth  width of one animation frame in pixels
     * @param frameHeight height of one animation frame in pixels
     * @param fps         playback fps (strip layout; grid rows override per-row)
     * @param loop        whether animation loops (strip; grid rows override)
     * @param rows        row definitions (only for grid layout)
     * @param defaultRow  default row index (only for grid layout)
     */
    public record AnimationEntry(
            String file,
            String layout,
            String renderMode,
            int columns,
            int frameWidth,
            int frameHeight,
            int fps,
            boolean loop,
            List<RowDef> rows,
            int defaultRow
    ) {
        /** Strip constructor (always sprite mode) */
        public AnimationEntry(String file, int columns, int frameWidth, int frameHeight,
                              int fps, boolean loop) {
            this(file, "strip", "sprite", columns, frameWidth, frameHeight, fps, loop, List.of(), 0);
        }
    }

    /**
     * Row definition for grid layouts.
     * For overlay renderMode, tint and opacity define the visual appearance.
     * For sprite renderMode, tint and opacity are null/ignored.
     */
    public record RowDef(
            int rowIndex,
            Condition condition,
            String tint,
            Double opacity,
            int fps,
            boolean loop
    ) {
        /** Backward-compat constructor without tint/opacity (sprite mode) */
        public RowDef(int rowIndex, Condition condition, int fps, boolean loop) {
            this(rowIndex, condition, null, null, fps, loop);
        }
    }

    /**
     * Condition for selecting a row.
     */
    public record Condition(
            String type,
            String value
    ) {}
}
